What does this program print?

```cpp
#include <iostream>

class Box {
    int m_val;
public:
    Box(int v) : m_val{ v } {}
    Box(const Box& src) : m_val{ src.m_val } {
        std::cout << "copy\n";
    }
    int get() const { return m_val; }
};

void show(Box b) {
    std::cout << b.get() << "\n";
}

int main() {
    Box b{ 5 };
    show(b);
}
```

How many times does the copy constructor run?

```cpp
#include <iostream>

class Tag {
    int m_n;
public:
    Tag(int n) : m_n{ n } {}
    Tag(const Tag& t) : m_n{ t.m_n } {
        std::cout << "C";
    }
};

void use(const Tag& t) {}
void copy(Tag t) {}

int main() {
    Tag a{ 1 };
    Tag b{ a };   // (1)
    use(b);       // (2)
    copy(b);      // (3)
    std::cout << "\n";
}
```
